        var D = $(".myemail");
        D.next().hide();
        D.text(C);
        D.attr("href", "mailto:" + C).unbind("click");
        D.fadeIn(1000)//这个1000是淡出的时间，单位毫秒；
    },1)
});
```

## 图片悬停半透明

效果大家把鼠标放在侧栏上面的广告图片或者用户评论排行榜的头像上就看得到，鼠标放上去后会出现半透明的效果。 

```javascript
$('img').hover(function() {
    $(this).animate({
        'opacity': .5//鼠标放上去后，透明度50%；
    })
},function() {
